# supertools/superRenderer.py

import os

class SuperRenderer:
    def __init__(self, template_dir="templates"):
        self.template_dir = template_dir

    def render(self, template_name, context, format="html"):
        tpl_path = os.path.join(self.template_dir, template_name)
        if not os.path.exists(tpl_path):
            return f"[ERROR] Template {template_name} not found"
        with open(tpl_path, "r") as f:
            tpl = f.read()
        # Simple variable replace for {{ var }} in .tpl
        for k, v in context.items():
            tpl = tpl.replace("{{ " + k + " }}", str(v))
        if format == "json":
            import json
            return json.dumps(context, indent=2)
        return tpl

# Ex test
if __name__ == "__main__":
    r = SuperRenderer(template_dir="../templates")
    html = r.render("components/components.tpl", {"title": "Hello", "body": "Ceci est un test"})
    print(html)

